original_code:
module TopModule (
    input wire S,
    input wire R,
    output wire Q,
    output wire Qn
);
    wire Q_reg;

    assign Qn = ~Q_reg;

    always @(S, R) begin
        if (S && !R) 
            Q_reg <= 1; // Set
        else if (!S && R) 
            Q_reg <= 0; // Reset
        // If both S and R are 0, maintain the previous state (Q_reg)
        // If both S and R are 1, the state is undefined, so we do nothing.
    end

    assign Q = Q_reg;
endmodule

